import{_ as t,o as r,c as e,ai as a}from"./chunks/framework.DMjte4z8.js";const h=JSON.parse('{"title":"计时器触发器：制作倒计时和定时事件","description":"","frontmatter":{"title":"计时器触发器：制作倒计时和定时事件","category":"triggers","updated":"2026-04-28T00:00:00.000Z","model":"openai/MiniMax-M2.7-highspeed","quality_score":0.84,"discovered_via":"manual","sources":["https://world-editor-tutorials.thehelper.net/cat_usersubmit.php?view=53421","https://www.youtube.com/watch?v=fCZGn2o8Ccw","https://www.youtube.com/watch?v=maAvnT0fkuI","https://hobbies.thombedford.com/74","https://wc3we.fandom.com/wiki/GUI_Triggering"]},"headers":[],"relativePath":"triggers/计时器触发器制作倒计时和定时事件.md","filePath":"triggers/计时器触发器制作倒计时和定时事件.md","lastUpdated":1777383225000}'),l={name:"triggers/计时器触发器制作倒计时和定时事件.md"};function i(n,o,s,u,g,q){return r(),e("div",null,[...o[0]||(o[0]=[a('<h1 id="计时器触发器-制作倒计时和定时事件" tabindex="-1">计时器触发器：制作倒计时和定时事件 <a class="header-anchor" href="#计时器触发器-制作倒计时和定时事件" aria-label="Permalink to “计时器触发器：制作倒计时和定时事件”">​</a></h1><h2 id="什么是计时器触发器" tabindex="-1">什么是计时器触发器 <a class="header-anchor" href="#什么是计时器触发器" aria-label="Permalink to “什么是计时器触发器”">​</a></h2><p>计时器触发器是魔兽争霸III地图编辑器中用来<strong>计时和定时执行操作</strong>的工具。简单来说，它就像一个&quot;闹钟&quot;——你可以设定好时间，等时间到了，系统就会自动执行你事先写好的指令。在本节中，你将理解什么是计时器触发器，以及它为什么对你的RPG地图非常重要。</p><h3 id="计时器触发器的作用与用途" tabindex="-1">计时器触发器的作用与用途 <a class="header-anchor" href="#计时器触发器的作用与用途" aria-label="Permalink to “计时器触发器的作用与用途”">​</a></h3><p>计时器触发器主要有两大功能[^1]：</p><ol><li><strong>倒计时功能</strong> — 在屏幕上显示一个倒计时器，比如&quot;距离下一波敌人还有30秒&quot;，让玩家知道将要发生什么</li><li><strong>定时触发功能</strong> — 当时间到达后，自动执行一系列预设的动作，比如生成怪物、给予奖励、切换游戏阶段等</li></ol><p>你可以把计时器想象成一张&quot;时间表&quot;——你在上面写下&quot;10秒后做XXX&quot;，然后交给系统去执行，而你可以腾出手来做其他事情。</p><h3 id="计时器在rpg地图中的应用场景" tabindex="-1">计时器在RPG地图中的应用场景 <a class="header-anchor" href="#计时器在rpg地图中的应用场景" aria-label="Permalink to “计时器在RPG地图中的应用场景”">​</a></h3><p>在RPG地图中，计时器触发器的应用非常广泛[^2][^3]：</p><ul><li><strong>波次刷怪系统</strong> — 每隔一段时间自动生成一波敌人进攻玩家[^2]</li><li><strong>召唤计时器</strong> — 玩家站在特定区域（如&quot;力量之圈&quot;）等待几秒后获得召唤生物[^3]</li><li><strong>Buff持续时间</strong> — 追踪玩家获得的增益/减益效果还剩多久</li><li><strong>任务倒计时</strong> — 给任务添加时间限制，增加紧张感</li><li><strong>游戏阶段切换</strong> — 比如&quot;10分钟后Boss出现&quot;</li></ul><h3 id="操作步骤" tabindex="-1">操作步骤 <a class="header-anchor" href="#操作步骤" aria-label="Permalink to “操作步骤”">​</a></h3><p>创建一个最基本的计时器触发器，只需三步：</p><ol><li><strong>创建计时器变量</strong> — 在触发器编辑器左侧，右键点击&quot;变量&quot;，选择&quot;新建变量&quot;，名称输入<code>MyTimer</code>，类型选择&quot;计时器&quot;，然后点击确定[^4]</li><li><strong>设置计时器并启动</strong> — 在触发器中添加动作&quot;计时器 - 启动计时器&quot;，选择你的<code>MyTimer</code>变量，类型设为&quot;单次&quot;（只执行一次）或&quot;重复&quot;（循环执行），时间设为需要的秒数</li><li><strong>设置倒计时窗口（可选）</strong> — 如果想让玩家看到倒计时，添加动作&quot;计时器 - 为MyTimer创建计时器窗口，标题为&#39;剩余时间&#39;&quot;，然后将结果保存到变量中[^1]</li></ol><h3 id="小结" tabindex="-1">小结 <a class="header-anchor" href="#小结" aria-label="Permalink to “小结”">​</a></h3><p>完成以上步骤后，你就掌握了一个计时器触发器的基本结构。计时器触发器由<strong>事件</strong>（启动计时器）、<strong>条件</strong>（可选）和<strong>动作</strong>（计时结束后的操作）三部分组成。搭配倒计时窗口显示，玩家就能直观地看到时间流逝。</p><blockquote><p><strong>💡 新手提示</strong>：计时器的&quot;单次&quot;和&quot;重复&quot;区别很大——单次计时器只会执行一次就停止，适合做&quot;延迟执行&quot;；重复计时器会不断循环，适合做&quot;每X秒执行一次&quot;的波次系统。</p></blockquote><blockquote><p><strong>⚠️ 常见错误</strong>：新手常忘记计时器需要配合&quot;计时器过期&quot;事件才能生效！一定要添加事件&quot;计时器 - MyTimer过期&quot;，否则计时器启动了但什么都不会发生。</p></blockquote><h2 id="计时器的基础知识" tabindex="-1">计时器的基础知识 <a class="header-anchor" href="#计时器的基础知识" aria-label="Permalink to “计时器的基础知识”">​</a></h2><p>本节我们将学习什么是&quot;计时器&quot;，以及如何在地图编辑器中创建计时器变量。计时器是魔兽争霸III地图中实现倒计时、定时事件的核心工具——学完后，你将能够为游戏添加波次进攻的倒计时显示、技能冷却提示等功能。</p><h3 id="什么是计时器" tabindex="-1">什么是计时器？ <a class="header-anchor" href="#什么是计时器" aria-label="Permalink to “什么是计时器？”">​</a></h3><p>计时器（Timer）是一种特殊的变量类型，你可以把它理解为一个&quot;倒计时闹钟&quot;。当你启动一个计时器时，你可以设定它倒计时多久，时间归零时会触发你设定好的事件。</p><h3 id="一次性计时器与周期计时器的区别" tabindex="-1">一次性计时器与周期计时器的区别 <a class="header-anchor" href="#一次性计时器与周期计时器的区别" aria-label="Permalink to “一次性计时器与周期计时器的区别”">​</a></h3><p>计时器有两种工作模式，理解它们的区别非常重要：</p><ul><li><strong>一次性计时器（One-shot Timer）</strong>：只倒计时一次，时间到了触发一次事件后自动停止。比如设定30秒后显示&quot;战斗开始&quot;，显示一次就够了。</li><li><strong>周期计时器（Periodic Timer）</strong>：会不断重复倒计时。比如设定每5秒自动生成一波敌人，它会一直循环执行[^2]。</li></ul><blockquote><p><strong>💡 新手提示</strong>：选择哪种模式取决于你的需求——只需要执行一次用一次性计时器，需要反复执行用周期计时器。</p></blockquote><h3 id="计时器变量的创建与管理" tabindex="-1">计时器变量的创建与管理 <a class="header-anchor" href="#计时器变量的创建与管理" aria-label="Permalink to “计时器变量的创建与管理”">​</a></h3><p>在WE（World Editor，世界编辑器）中，计时器需要先创建&quot;变量&quot;来存储和管理。下面是创建步骤：</p><ol><li><strong>打开变量编辑器</strong> — 在顶部菜单栏点击&quot;编辑&quot;→&quot;变量&quot;（快捷键 Ctrl+B）[^1]</li><li><strong>新建变量</strong> — 点击左上角的绿色&quot;+&quot;按钮添加新变量</li><li><strong>设置变量名</strong> — 在&quot;变量名称&quot;框输入名字，比如 <code>MyTimer</code>（注意：名字不能有空格）</li><li><strong>选择变量类型</strong> — 在下拉菜单中找到并选择 <code>计时器</code>（Timer）类型</li><li><strong>点击确认</strong> — 点击&quot;确定&quot;按钮完成创建</li></ol><blockquote><p><strong>⚠️ 常见错误</strong>：新手经常忘记创建变量，直接在触发器里使用计时器动作，这会导致计时器无法被正确引用和管理。一定要先创建变量！</p></blockquote><h3 id="小结-1" tabindex="-1">小结 <a class="header-anchor" href="#小结-1" aria-label="Permalink to “小结”">​</a></h3><p>完成以上步骤后，你已经学会了：</p><ul><li>计时器的两种模式（一次性 vs 周期）</li><li>如何创建计时器变量</li></ul><p>接下来我们将在触发器中实际使用这个计时器变量，实现真正的倒计时功能！</p><h2 id="创建简单倒计时" tabindex="-1">创建简单倒计时 <a class="header-anchor" href="#创建简单倒计时" aria-label="Permalink to “创建简单倒计时”">​</a></h2><p>倒计时是RPG地图中最常用的功能之一——比如副本有时间限制、玩家挑战有准备时间、或者游戏结束时显示剩余时间。通过本节学习，你将创建一个60秒的简单倒计时器，并在时间归零时触发事件。</p><h3 id="倒计时触发器的创建步骤" tabindex="-1">倒计时触发器的创建步骤 <a class="header-anchor" href="#倒计时触发器的创建步骤" aria-label="Permalink to “倒计时触发器的创建步骤”">​</a></h3><ol><li><p><strong>第一步：创建计时器变量</strong> — 在触发器编辑器的&quot;变量&quot;面板中点击&quot;新建变量&quot;，命名为<code>MyTimer</code>，类型选择&quot;计时器（Timer）&quot;[^1]。变量就像是给东西起的名字，方便之后在代码里找到它。</p></li><li><p><strong>第二步：创建计时器</strong> — 新建一个触发器，事件选择&quot;地图初始化&quot;。动作依次添加：</p><ul><li>&quot;等待1.00秒&quot; — 给玩家一点准备时间[^1]</li><li>&quot;计时器 - 创建计时器窗口&quot;：选择<code>MyTimer</code>，时长设为60.00秒，标题填&quot;剩余时间：%s&quot;，点击确定[^1]</li></ul></li><li><p><strong>第三步：保存计时器窗口</strong> — 添加动作&quot;设置变量&quot;，把<code>MyTimerWindow</code>设为&quot;上一个创建的计时器窗口&quot;[^1]。这样你才能控制它显示或隐藏。</p></li><li><p><strong>第四步：让计时器显示出来</strong> — 在同一个触发器里继续添加动作&quot;计时器窗口 - 显示 MyTimerWindow&quot;[^1]。没有这一步，计时器虽然在工作，但玩家根本看不到！</p></li><li><p><strong>第五步：处理倒计时结束</strong> — 新建另一个触发器，事件选择&quot;计时器 - MyTimer过期&quot;。在这个触发器里添加你想做的任何事——播放音效、显示提示、生成怪物、判定胜负等。</p></li></ol><h3 id="小结-2" tabindex="-1">小结 <a class="header-anchor" href="#小结-2" aria-label="Permalink to “小结”">​</a></h3><p>完成以上步骤后，你应该能看到游戏屏幕上方显示&quot;剩余时间：60&quot;，数字每秒自动减少。当时间归零时，你设置的事件就会自动执行。你可以试着把60秒改成其他数字，或者在倒计时结束时添加不同的动作来加深理解。</p><h2 id="定时循环事件的实现" tabindex="-1">定时循环事件的实现 <a class="header-anchor" href="#定时循环事件的实现" aria-label="Permalink to “定时循环事件的实现”">​</a></h2><p>本节将教你如何创建能够<strong>自动重复执行</strong>的循环计时器。学完后，你能让游戏中的事件每隔一段时间自动发生，比如怪物每30秒自动刷新一次。</p><hr><h3 id="周期计时器的配置与启动" tabindex="-1">周期计时器的配置与启动 <a class="header-anchor" href="#周期计时器的配置与启动" aria-label="Permalink to “周期计时器的配置与启动”">​</a></h3><p>与一次性计时器不同，周期计时器会<strong>反复触发</strong>，直到你主动停止它。</p><p><strong>操作步骤：</strong></p><ol><li><p><strong>创建计时器变量</strong> — 在变量列表（Variable List）中点击新建，输入变量名 <code>MyLoopTimer</code>，类型选择 <code>Timer</code>[^1]</p></li><li><p><strong>设置计时器为周期模式</strong> — 在触发器编辑器中，添加动作 <code>计时器 - Start MyLoopTimer as a Periodic（周期）Timer with 5.00 seconds</code>[^2]</p><ul><li>这里的&quot;5.00 seconds&quot;表示每5秒触发一次，你可以根据需要调整</li></ul></li><li><p><strong>创建触发器响应</strong> — 新建一个触发器，<strong>事件</strong>选择 <code>计时器 - MyLoopTimer expires</code>（当计时器到期时）[^2]</p><ul><li>这个触发器会在计时器每次到期时自动执行</li></ul></li><li><p><strong>添加循环执行的动作</strong> — 在触发器中添加你想重复执行的动作，比如&quot;创建怪物单位&quot;或&quot;显示提示文字&quot;</p></li></ol><blockquote><p><strong>💡 新手提示</strong>：周期计时器一旦启动就会永久循环，除非你主动停止它。所以在使用前先想清楚：这个效果是否需要持续重复？</p></blockquote><hr><h3 id="循环触发器的停止与销毁" tabindex="-1">循环触发器的停止与销毁 <a class="header-anchor" href="#循环触发器的停止与销毁" aria-label="Permalink to “循环触发器的停止与销毁”">​</a></h3><p>如果忘记停止周期计时器，会导致触发器不断执行，轻则影响游戏性能，重则引发崩溃。</p><p><strong>操作步骤：</strong></p><ol><li><p><strong>创建停止条件</strong> — 在需要停止循环的地方（比如玩家完成任务），添加条件判断，例如检查一个布尔变量 <code>任务完成 = True</code>[^4]</p></li><li><p><strong>添加停止计时器动作</strong> — 在触发器中添加 <code>计时器 - Pause MyLoopTimer</code>（暂停计时器）[^5]</p><ul><li>这会立即停止计时器的循环</li></ul></li><li><p><strong>销毁计时器释放内存</strong> — 再添加 <code>计时器 - Destroy MyLoopTimer</code>[^5]</p><ul><li>这一步很重要！不销毁计时器会占用电脑内存，就像打开太多网页会让电脑变慢一样</li></ul></li></ol><blockquote><p><strong>⚠️ 常见错误</strong>：很多新手只记得&quot;暂停&quot;计时器，忘了&quot;销毁&quot;它。运行时间久了游戏会越来越卡。<strong>暂停和销毁必须同时使用</strong>，缺一不可！</p></blockquote><hr><h3 id="小结-3" tabindex="-1">小结 <a class="header-anchor" href="#小结-3" aria-label="Permalink to “小结”">​</a></h3><p>完成以上步骤后，你应该：</p><ul><li>✅ 能创建一个每X秒自动执行一次的周期计时器</li><li>✅ 能在适当时机正确停止并销毁计时器</li><li>✅ 理解&quot;暂停&quot;和&quot;销毁&quot;的区别，两者缺一不可</li></ul><blockquote><p><strong>🎯 动手试试</strong>：创建一个每10秒给所有玩家发送&quot;波次即将到来&quot;提示的循环计时器，然后手动输入 <code>/ victory</code> 聊天命令时停止并销毁它。</p></blockquote><h2 id="计时器与游戏状态的结合" tabindex="-1">计时器与游戏状态的结合 <a class="header-anchor" href="#计时器与游戏状态的结合" aria-label="Permalink to “计时器与游戏状态的结合”">​</a></h2><p>本节将学习如何在同一张地图中同时运行多个计时器（并行管理），以及当玩家暂停游戏时计时器会发生什么变化。掌握这些技巧后，你就能制作出更复杂的事件系统，比如同时追踪多个倒计时。</p><h3 id="多计时器的并行管理" tabindex="-1">多计时器的并行管理 <a class="header-anchor" href="#多计时器的并行管理" aria-label="Permalink to “多计时器的并行管理”">​</a></h3><p>什么是&quot;并行&quot;？简单说就是<strong>同时运行</strong>。想象你在做饭时可以同时煮汤和炒菜——计时器也可以这样，每个计时器各走各的，互不干扰。</p><ol><li><p><strong>第一步：创建多个计时器变量</strong> — 在变量列表中新建变量，类型选择&quot;计时器&quot;（Timer），分别命名为 TimerA、TimerB、TimerC[^1]。注意每个计时器变量只能对应一个计时器。</p></li><li><p><strong>第二步：为每个计时器创建独立触发器</strong> — 新建触发器，添加事件&quot;计时器 - TimerA 到期&quot;，再添加对应动作。比如第一个计时器到期后生成一波敌人[^2]。</p></li><li><p><strong>第三步：在需要的地方启动计时器</strong> — 使用动作&quot;计时器 - 开始&quot;，设置 TimerA 为30秒一次性计时。在游戏的任何时刻，你都可以再启动 TimerB、TimerC，它们会同时倒数[^2]。</p></li><li><p><strong>第四步：给计时器配备独立的窗口</strong> — 如果想让玩家看到每个倒计时，可以用&quot;计时器窗口 - 为计时器创建窗口&quot;动作创建多个显示窗口，分别设置不同的标题[^1]。</p></li></ol><blockquote><p><strong>💡 新手提示</strong>：给每个计时器变量起一个有意义的名字，比如&quot;FightCountdown&quot;（战斗倒计时）、&quot;WaveTimer&quot;（波次计时器），这样触发器多了以后自己也能看懂。</p></blockquote><blockquote><p><strong>⚠️ 常见错误</strong>：新手容易犯的错是只用一个计时器变量但想同时管理多个倒计时。比如设置了30秒的倒计时，又想再设置一个60秒的倒计时，但复用了同一个变量，结果两个倒计时互相覆盖。<strong>解决方法</strong>是每个独立运行的计时器都必须有自己专属的变量。</p></blockquote><h3 id="游戏暂停对计时器的影响" tabindex="-1">游戏暂停对计时器的影响 <a class="header-anchor" href="#游戏暂停对计时器的影响" aria-label="Permalink to “游戏暂停对计时器的影响”">​</a></h3><p>&quot;游戏暂停&quot;功能允许玩家按 ESC 键暂停游戏。在默认设置下，<strong>计时器在暂停时会停止计时</strong>——这对某些情况可能是你想要的，但也可能不是。</p><ol><li><p><strong>第一步：了解默认行为</strong> — 创建两个触发器：一个启动计时器，另一个在计时器到期时显示消息。运行地图，按 ESC 暂停游戏，你会发现计时器停在原处不动了。</p></li><li><p><strong>第二步：如果需要暂停时继续计时</strong> — 这是高级技巧，需要使用&quot;游戏 - 暂停计时器&quot;和&quot;游戏 - 恢复计时器&quot;动作。创建一个辅助触发器，事件设为&quot;游戏 - 玩家暂停游戏&quot;，动作是&quot;游戏 - 恢复 TimerA&quot;。但请注意，<strong>恢复计时器需要你手动追踪暂停期间过去了多少真实时间</strong>，实现较复杂。</p></li><li><p><strong>第三步：更简单的替代方案</strong> — 如果你只是想在暂停时不让玩家看到倒计时窗口，可以用&quot;计时器窗口 - 显示/隐藏&quot;动作，在暂停时隐藏窗口[^1]。</p></li></ol><blockquote><p><strong>💡 新手提示</strong>：对于大多数 RPG 地图来说，默认的&quot;暂停时计时器停止&quot;行为其实是合理的——给玩家暂停时思考的时间，但倒计时暂停也是公平的。</p></blockquote><blockquote><p><strong>⚠️ 常见错误</strong>：新手误以为&quot;游戏 - 暂停游戏&quot;动作会影响计时器运行。实际上这两个是完全独立的系统，暂停游戏<strong>不会</strong>自动暂停计时器，它们是分开工作的。</p></blockquote><h3 id="小结-4" tabindex="-1">小结 <a class="header-anchor" href="#小结-4" aria-label="Permalink to “小结”">​</a></h3><p>完成以上步骤后，你应该能：</p><ul><li>在同一张地图中创建和运行多个独立的计时器，每个计时器互不干扰</li><li>为不同的计时器创建各自的可视化倒计时窗口</li><li>理解游戏暂停与计时器运行的关系，知道如何根据需求选择合适的方案</li></ul><p>记住：<strong>每个同时运行的计时器 = 一个独立的计时器变量</strong>。这是多计时器管理的核心原则。</p><h2 id="常见问题与调试技巧" tabindex="-1">常见问题与调试技巧 <a class="header-anchor" href="#常见问题与调试技巧" aria-label="Permalink to “常见问题与调试技巧”">​</a></h2><p>本节将帮助你解决计时器触发器使用过程中最常见的两个问题：<strong>计时器不准怎么办</strong>以及<strong>如何防止内存泄漏</strong>。学完本节后，你将能够自己排查和修复计时器相关的问题，让你的倒计时功能稳定运行。</p><h3 id="计时器精度与延迟问题" tabindex="-1">计时器精度与延迟问题 <a class="header-anchor" href="#计时器精度与延迟问题" aria-label="Permalink to “计时器精度与延迟问题”">​</a></h3><p>计时器不准确是新手最常遇到的问题。你设置的10秒倒计时，可能实际走了12秒，或者突然变快变慢。这通常是因为<strong>触发器的&quot;等待&quot;动作</strong>（Wait）会受到游戏整体卡顿的影响——当游戏画面加载、技能特效较多时，等待时间会被&quot;拖延&quot;。[^1]</p><p><strong>排查步骤：</strong></p><ol><li><p><strong>检查是否有大量特效或单位同时出现</strong> — 这些会占用系统资源，导致计时器延迟。在测试地图时关闭其他无关触发器，单独测试计时器。[^2]</p></li><li><p><strong>确认计时器是&quot;一次性&quot;还是&quot;循环&quot;的</strong> — 如果你设置了循环计时器但只触发了一次，可能是因为触发器条件没有正确重置。检查触发器是否使用了&quot;开启/关闭触发器&quot;动作。[^2]</p></li><li><p><strong>使用调试信息验证计时器状态</strong> — 在触发器中添加&quot;显示教程文本&quot;动作，实时打印计时器剩余时间，观察数值是否按预期减少。[^1]</p></li></ol><blockquote><p><strong>⚠️ 常见错误</strong>：新手经常把&quot;等待&quot;动作（Wait）和&quot;计时器过期&quot;事件混淆。<strong>等待是暂停一段时间后继续执行后续动作，不会自动创建倒计时窗口</strong>；而<strong>计时器过期事件</strong>才是真正的定时触发。如果你需要显示倒计时界面，必须使用&quot;计时器 - 创建计时器窗口&quot;动作。[^1]</p></blockquote><blockquote><p><strong>💡 新手提示</strong>：在调试计时器时，在触发器开头添加一个&quot;显示教程文本&quot;动作，打印&quot;计时器已启动！&quot;，这样你可以确认触发器是否真的被激活了。有时候问题不是计时器不准，而是计时器根本没开始！</p></blockquote><h3 id="计时器内存泄漏的预防" tabindex="-1">计时器内存泄漏的预防 <a class="header-anchor" href="#计时器内存泄漏的预防" aria-label="Permalink to “计时器内存泄漏的预防”">​</a></h3><p><strong>内存泄漏</strong>听起来很专业，其实可以这样理解：你的电脑就像一个房间，计时器就像放进房间的物品。每次创建计时器时，电脑会分配一小块&quot;空间&quot;来记住它。当计时器用完时，这块空间应该被&quot;归还&quot;——但如果你忘记归还（没有正确销毁计时器），这块空间就会一直被占用，久而久之房间就满了，游戏就会变卡甚至崩溃。</p><p><strong>预防内存泄漏的步骤：</strong></p><ol><li><p><strong>每次创建计时器时，立刻创建一个同名的变量来保存它</strong> — 这样你才能在后面准确地销毁它。[^1] 例如：创建计时器 → 设置 MyTimer = (Last created timer)</p></li><li><p><strong>在使用完计时器后，立即使用&quot;计时器 - 销毁&quot;动作</strong> — 在触发器中添加这个动作，确保计时器被正确清理。[^1] 可以放在&quot;计时器过期&quot;事件的处理中，也可以放在触发器最后。</p></li><li><p><strong>避免在循环触发器中反复创建新计时器而不销毁</strong> — 如果你的波次系统每波都创建新计时器，一定要确保上一波的计时器已被销毁。[^2] 建议在创建新计时器之前先检查旧计时器是否存在，若存在则先销毁。</p></li></ol><blockquote><p><strong>💡 新手提示</strong>：养成习惯——<strong>创建计时器 = 必须销毁计时器</strong>。就像你拿了一本书，用完必须放回书架。可以把这个规则写在你电脑旁边的便签上！</p></blockquote><blockquote><p><strong>⚠️ 常见错误</strong>：新手以为只要计时器时间走完就会自动消失，不用手动销毁。这是一个误解！<strong>计时器过期只表示它触发了事件，但计时器本身仍然占用内存</strong>，必须手动用&quot;销毁&quot;动作清理它。[^1]</p></blockquote><h3 id="小结-5" tabindex="-1">小结 <a class="header-anchor" href="#小结-5" aria-label="Permalink to “小结”">​</a></h3><p>通过本节的学习，你应该掌握了：</p><ul><li>当计时器不准时，先排除其他触发器的干扰，再用调试文本验证计时器是否正常工作</li><li>记住&quot;等待&quot;和&quot;计时器过期事件&quot;的区别——前者只是暂停，后者才是真正的定时触发[^1]</li><li>每次创建计时器后都要想着销毁它，形成&quot;创必销毁&quot;的好习惯</li></ul><p>现在你可以回到你的地图中，用这些方法检查之前创建的计时器触发器，看看有没有遗漏的问题！</p><h2 id="参考来源" tabindex="-1">参考来源 <a class="header-anchor" href="#参考来源" aria-label="Permalink to “参考来源”">​</a></h2><p>[^1]: <a href="https://world-editor-tutorials.thehelper.net/cat_usersubmit.php?view=53421" target="_blank" rel="noreferrer">Triggers - Countdown Timers - World Editor Tutorials</a> — accessed 2026-04-28 [^2]: <a href="https://www.youtube.com/watch?v=fCZGn2o8Ccw" target="_blank" rel="noreferrer">Theef&#39;s Warcraft 3 World Editor Tutorial #14 - Waves (and Timers)</a> — accessed 2026-04-28 [^3]: <a href="https://www.youtube.com/watch?v=maAvnT0fkuI" target="_blank" rel="noreferrer">Warcraft 3 World Editor Tutorial: Summon Timers</a> — accessed 2026-04-28 [^4]: <a href="https://hobbies.thombedford.com/74" target="_blank" rel="noreferrer">Warcraft III World Editor Tutorial – 11: Once-Only Triggers</a> — accessed 2026-04-28 [^5]: <a href="https://wc3we.fandom.com/wiki/GUI_Triggering" target="_blank" rel="noreferrer">GUI Triggering | Warcraft 3 World Editor Wiki - Fandom</a> — accessed 2026-04-28</p>',94)])])}const c=t(l,[["render",i]]);export{h as __pageData,c as default};
